911: 	var fs notify.FanoutStage
912: 	for i := range integrations {
913: 		recv := &nflogpb.Receiver{
914: 			GroupName:   name,
915: 			Integration: integrations[i].Name(),
916: 			Idx:         uint32(integrations[i].Index()),
917: 		}
918: 		var s notify.MultiStage
919: 		s = append(s, stages.NewWaitStage(am.opts.Peer, am.opts.PeerTimeout))
920: 		s = append(s, notify.NewDedupStage(integrations[i], notificationLog, recv))
921: 		s = append(s, notify.NewRetryStage(integrations[i], name, am.stageMetrics))
922: 		s = append(s, notify.NewSetNotifiesStage(notificationLog, recv))
923: 
924: 		fs = append(fs, s)
925: 	}
926: 	return fs
927: }
