933: func (am *GrafanaAlertmanager) timeoutFunc(d time.Duration) time.Duration {
934: 	// time.Duration d relates to the receiver's group_interval. Even with a group interval of 1s,
935: 	// we need to make sure (non-position-0) peers in the cluster wait before flushing the notifications.
936: 	if d < notify.MinTimeout {
937: 		d = notify.MinTimeout
938: 	}
939: 	return d + am.waitFunc()
