{"content":"145: // Match does a depth-first left-to-right search through the route tree
146: // and returns the matching routing nodes.
147: func (r *Route) Match(lset model.LabelSet) []*Route {
148: 	if !r.Matchers.Matches(lset) {
149: 		return nil
150: 	}
151: 
152: 	var all []*Route
153: 
154: 	for _, cr := range r.Routes {
155: 		matches := cr.Match(lset)
156: 
157: 		all = append(all, matches...)
158: 
159: 		if matches != nil && !cr.Continue {
160: 			break
161: 		}
162: 	}
163: 
164: 	// If no child nodes were matches, the current node itself is a match.
165: 	if len(all) == 0 {
166: 		all = append(all, r)
167: 	}
168: 
169: 	return all
170: }
